@implements IAsyncDisposable

<CascadingValue Value="_screenSize" Name="ScreenSize">
    @ChildContent
</CascadingValue>

@code {
    [Parameter]
    public RenderFragment? ChildContent { get; set; }

    private ScreenSize _screenSize = ScreenSize.Desktop;
    private IJSObjectReference? _jsModule;
    private DotNetObjectReference<ScreenSizeProvider>? _dotNetRef;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _dotNetRef = DotNetObjectReference.Create(this);
            _jsModule = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./_content/ScreenSizeProvider.razor.js");
            await _jsModule.InvokeVoidAsync("initialize", _dotNetRef);
        }
    }

    [JSInvokable]
    public void OnViewportWidthChanged(int width)
    {
        var newSize = width switch
        {
            < 768 => ScreenSize.Mobile,
            < 1024 => ScreenSize.Tablet,
            _ => ScreenSize.Desktop
        };

        if (newSize != _screenSize)
        {
            _screenSize = newSize;
            StateHasChanged();
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_jsModule is not null)
        {
            try
            {
                await _jsModule.InvokeVoidAsync("dispose");
                await _jsModule.DisposeAsync();
            }
            catch (JSDisconnectedException) { }
        }
        _dotNetRef?.Dispose();
    }

    [Inject]
    private IJSRuntime JS { get; set; } = default!;
}

namespace sv_0bcff1e278b5486d8bf46cdf82f7eba2.Components;

public enum ScreenSize
{
    Mobile,
    Tablet,
    Desktop
}

let dotNetRef = null;
let resizeHandler = null;

export function initialize(ref) {
    dotNetRef = ref;
    resizeHandler = () => {
        dotNetRef.invokeMethodAsync('OnViewportWidthChanged', window.innerWidth);
    };
    window.addEventListener('resize', resizeHandler);
    // Send the initial width immediately
    dotNetRef.invokeMethodAsync('OnViewportWidthChanged', window.innerWidth);
}

export function dispose() {
    if (resizeHandler) {
        window.removeEventListener('resize', resizeHandler);
        resizeHandler = null;
    }
    dotNetRef = null;
}

